return $input.all().map(item => ({
  json: {
    message: `🎉 *JOYEUX ANNIVERSAIRE !* 🎉

Cher(e) *${item.json.prenom} ${item.json.nom}*,

À l'occasion de votre anniversaire, nous vous adressons nos plus sincères félicitations et nos meilleurs vœux de santé, de bonheur et de réussite, tant sur le plan personnel que professionnel.

📋 *Vos informations*
• Code X3 : ${item.json.code_x3}
• Date de naissance : ${item.json.date_naissance}
• Date d'entrée : ${item.json.date_entree}
• Ancienneté : ${item.json.anciennete_affichage}
• Poste : ${item.json.Poste}
• Email : ${item.json.Email}

✨ Nous vous remercions pour votre engagement, votre professionnalisme et votre précieuse contribution au sein de *Jbel Annour*. Nous vous souhaitons une excellente journée d'anniversaire ainsi qu'une année riche en succès, en accomplissements et en moments de bonheur.

Avec nos meilleures salutations,

🤖 *Assistante IA de Mme Salma Sarhrany*
*Service des Ressources Humaines*
*Société Jbel Annour* 🎂🎁`,
    email: item.json.Email
  }
}));

// Récupère tous les résultats de la requête SQL
const employees = $input.all();

// Aucun salarié concerné : ne rien envoyer
if (employees.length === 0) {
  return [];
}

// Construction du message
let message = `🚨 *ALERTE RH - Supérieurs inactifs*\n\n`;
message += `Les salariés suivants sont encore rattachés à un supérieur qui a quitté l'entreprise ou qui n'est plus actif.\n\n`;

employees.forEach((emp, index) => {
  message += `👤 *${index + 1}. ${emp.json["Nom & Prénom"]}*\n`;
  message += `📋 Code X3 : ${emp.json["Code X3"]}\n`;
  message += `🆔 Matricule : ${emp.json["Matricule"]}\n`;
  message += `👨‍💼 Supérieur : ${emp.json["Supérieur"]}\n`;
  message += `📌 Code X3 Supérieur : ${emp.json["Code X3 Sup"]}\n\n`;
});

message += `━━━━━━━━━━━━━━━━━━━━━━\n`;
message += `📊 *Total des salariés concernés : ${employees.length}*\n\n`;
message += `⚠️ Merci de mettre à jour le rattachement hiérarchique dans Sage X3.\n`;
message += `\n🤖 Notification automatique - Assistant IA RH`;

return [
  {
    json: {
      total: employees.length,
      message: message
    }
  }
];
